import{c as a,Q as e,j as n,m as s}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Agent Harness 深度研究","description":"","frontmatter":{"title":"Agent Harness 深度研究","type":"documentation"},"headers":[],"relativePath":"research/agent-harness/RESEARCH.md","filePath":"research/agent-harness/RESEARCH.md","lastUpdated":1779894392000}'),r={name:"research/agent-harness/RESEARCH.md"};function o(i,t,l,d,h,p){return e(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="agent-harness-深度研究" tabindex="-1">Agent Harness 深度研究 <a class="header-anchor" href="#agent-harness-深度研究" aria-label="Permalink to &quot;Agent Harness 深度研究&quot;">​</a></h1><blockquote><p>研究分支：<code>claude/agent-harness-research-eM6Vc</code> 完成日：2026-04-30 觸發：Zeuik 提供的 LinkedIn 長文（OpenClaw vs Claude Code 體感差異分析）</p></blockquote><hr><h2 id="研究背景" tabindex="-1">研究背景 <a class="header-anchor" href="#研究背景" aria-label="Permalink to &quot;研究背景&quot;">​</a></h2><p>同樣是 Opus 4.6，OpenClaw 寫 code 普通，Claude Code 寫 code 強。不是模型問題，是「身體」和「約束」被調去解不同問題。這個觀察引出了一個更深的問題：</p><p><strong>Agent 的能力上限到底是由什麼決定的？</strong></p><hr><h2 id="核心等式的演化" tabindex="-1">核心等式的演化 <a class="header-anchor" href="#核心等式的演化" aria-label="Permalink to &quot;核心等式的演化&quot;">​</a></h2><h3 id="原始等式-langchain-viv-trivedy" tabindex="-1">原始等式（LangChain / Viv Trivedy） <a class="header-anchor" href="#原始等式-langchain-viv-trivedy" aria-label="Permalink to &quot;原始等式（LangChain / Viv Trivedy）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent = Model + Harness</span></span></code></pre></div><blockquote><p>「If you&#39;re not the model, you&#39;re the harness. A harness is every piece of code, configuration, and execution logic that isn&#39;t the model itself. A raw model is not an agent.」 — Viv Trivedy, LangChain</p></blockquote><h3 id="精化等式-zeuik-工作框架" tabindex="-1">精化等式（Zeuik 工作框架） <a class="header-anchor" href="#精化等式-zeuik-工作框架" aria-label="Permalink to &quot;精化等式（Zeuik 工作框架）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent = Model + Body + Harness</span></span></code></pre></div><p>這不是術語修正，是<strong>本質區分</strong>：</p><table tabindex="0"><thead><tr><th>層</th><th>定義</th><th>解的問題</th><th>典型組件</th></tr></thead><tbody><tr><td><strong>Model</strong></td><td>大腦，intelligence 本身</td><td>推理、理解、生成</td><td>GPT-5 / Claude Opus 4.7</td></tr><tr><td><strong>Body</strong></td><td>手腳，能力延伸</td><td>能不能做事</td><td>bash、filesystem、MCP、browser、sandbox</td></tr><tr><td><strong>Harness</strong></td><td>約束，行為校準</td><td>會不會做歪</td><td>CLAUDE.md、hooks、planner-evaluator、sub-agent 結構</td></tr></tbody></table><p><strong>關鍵區分</strong>：body 解決「能力存在」，harness 解決「行為可預測」。沒有手腳的大腦只能空想；沒有約束的手腳會做歪。</p><hr><h2 id="實驗數據-harness-的量化貢獻" tabindex="-1">實驗數據：Harness 的量化貢獻 <a class="header-anchor" href="#實驗數據-harness-的量化貢獻" aria-label="Permalink to &quot;實驗數據：Harness 的量化貢獻&quot;">​</a></h2><h3 id="terminal-bench-2-0-同模型不同-harness-的分數差距" tabindex="-1">Terminal-Bench 2.0：同模型不同 Harness 的分數差距 <a class="header-anchor" href="#terminal-bench-2-0-同模型不同-harness-的分數差距" aria-label="Permalink to &quot;Terminal-Bench 2.0：同模型不同 Harness 的分數差距&quot;">​</a></h3><p>Claude Opus 4.6 在相同 benchmark 上：</p><table tabindex="0"><thead><tr><th>Harness</th><th>準確度</th></tr></thead><tbody><tr><td>ForgeCode</td><td>79.8% ± 1.6</td></tr><tr><td>Capy</td><td>75.3% ± 2.4</td></tr><tr><td>TongAgents</td><td>71.9% ± 2.7</td></tr><tr><td>Crux</td><td>66.9%</td></tr></tbody></table><p><strong>結論：同一個 Opus 4.6，不同 harness 造成 13pp 分數差距。</strong></p><h3 id="stanford-meta-harness-研究" tabindex="-1">Stanford Meta-Harness 研究 <a class="header-anchor" href="#stanford-meta-harness-研究" aria-label="Permalink to &quot;Stanford Meta-Harness 研究&quot;">​</a></h3><p>同模型，harness 變化範圍：59.6% → 76.4%（16.8pp 差距）</p><h3 id="ewan-mak-實地案例-claude-sonnet-4-6" tabindex="-1">Ewan Mak 實地案例（Claude Sonnet 4.6） <a class="header-anchor" href="#ewan-mak-實地案例-claude-sonnet-4-6" aria-label="Permalink to &quot;Ewan Mak 實地案例（Claude Sonnet 4.6）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>階段</th><th>準確度</th><th>方法</th></tr></thead><tbody><tr><td>Baseline</td><td>58%</td><td>無優化</td></tr><tr><td>After harness optimization</td><td>81%</td><td>提示優化 + subagent 委派 + 中介觀測</td></tr></tbody></table><p><strong>結論：Harness 優化交付 15-25pp 提升，與模型升級效果相當。</strong></p><hr><h2 id="anthropic-april-23-postmortem-harness-級變更如何出包" tabindex="-1">Anthropic April 23 Postmortem：Harness 級變更如何出包 <a class="header-anchor" href="#anthropic-april-23-postmortem-harness-級變更如何出包" aria-label="Permalink to &quot;Anthropic April 23 Postmortem：Harness 級變更如何出包&quot;">​</a></h2><p>2026 年 3-4 月，Claude Code 品質下滑的三個根因：</p><table tabindex="0"><thead><tr><th>事件</th><th>時間</th><th>變更內容</th><th>影響</th></tr></thead><tbody><tr><td>Reasoning effort 降級</td><td>3/4</td><td>default: high → medium</td><td>「Claude 感覺不夠聰明」</td></tr><tr><td>Caching loop bug</td><td>3/26</td><td>thinking history 每輪清空（應每小時）</td><td>「forgetful and repetitive」</td></tr><tr><td>Verbosity 限制</td><td>4/16</td><td>系統提示加 ≤25/≤100 words 限制</td><td>Opus coding 品質下降 3%</td></tr></tbody></table><p><strong>官方承認</strong>：「The models themselves were not to blame, but three separate issues in the Claude Code harness caused complex but material problems which directly affected users.」</p><p><strong>關鍵教訓</strong>：Harness 改一行就能讓整個 output 分布跑掉，因為它直接校準分布。</p><hr><h2 id="context-rot-為什麼-sub-agent-是-context-firewall" tabindex="-1">Context Rot：為什麼 Sub-Agent 是 Context Firewall <a class="header-anchor" href="#context-rot-為什麼-sub-agent-是-context-firewall" aria-label="Permalink to &quot;Context Rot：為什麼 Sub-Agent 是 Context Firewall&quot;">​</a></h2><h3 id="chroma-實驗數據" tabindex="-1">Chroma 實驗數據 <a class="header-anchor" href="#chroma-實驗數據" aria-label="Permalink to &quot;Chroma 實驗數據&quot;">​</a></h3><ul><li>18 個模型在 NIAH（needle-in-a-haystack）任務上全部隨 context 增長而下降</li><li>即使是簡單任務（文字複製）在 2,500+ token 後也崩潰</li><li>加入語義相關但不正確的 distractor → 性能複合下降</li><li>悖論：隨機排列的 haystack 表現反而優於邏輯連貫文件（18 個模型一致）</li></ul><h3 id="實踐啟示" tabindex="-1">實踐啟示 <a class="header-anchor" href="#實踐啟示" aria-label="Permalink to &quot;實踐啟示&quot;">​</a></h3><p>Context rot 不能靠「更大的 context window」解決，只能靠結構性切割：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Sub-Agent = Context Firewall</span></span>
<span class="line"><span></span></span>
<span class="line"><span>主 Agent 只看到：</span></span>
<span class="line"><span>  → 給 sub-agent 的 prompt</span></span>
<span class="line"><span>  → sub-agent 的最終結論</span></span>
<span class="line"><span></span></span>
<span class="line"><span>中間過程（grep 輸出、工具呼叫、中間檔案讀取）</span></span>
<span class="line"><span>  → 留在 child context</span></span>
<span class="line"><span>  → 不污染主 thread</span></span></code></pre></div><hr><h2 id="anthropic-三層架構-planner-generator-evaluator" tabindex="-1">Anthropic 三層架構：Planner / Generator / Evaluator <a class="header-anchor" href="#anthropic-三層架構-planner-generator-evaluator" aria-label="Permalink to &quot;Anthropic 三層架構：Planner / Generator / Evaluator&quot;">​</a></h2><p>來自 Anthropic engineering blog《Harness Design for Long-Running Apps》：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User Brief</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>PLANNER AGENT</span></span>
<span class="line"><span>  └─ 轉成細粒度 spec（防止 scope 爆炸）</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>GENERATOR AGENT</span></span>
<span class="line"><span>  └─ 逐項實作</span></span>
<span class="line"><span>  └─ 遇到 context limit → 完整 reset（不靠摘要）</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>EVALUATOR AGENT</span></span>
<span class="line"><span>  └─ Playwright / 外部工具（非模型自評）</span></span>
<span class="line"><span>  └─ Hard threshold：任一失敗 → sprint 失敗</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>(Feedback Loop)</span></span></code></pre></div><p><strong>為什麼不能讓同一個 agent 自評</strong>：Generator 「自信地稱讚自己的工作，即使品質明顯平庸」——self-evaluation 永遠偏正向。</p><hr><h2 id="harness-的-11-大構件-stanford-分類" tabindex="-1">Harness 的 11 大構件（Stanford 分類） <a class="header-anchor" href="#harness-的-11-大構件-stanford-分類" aria-label="Permalink to &quot;Harness 的 11 大構件（Stanford 分類）&quot;">​</a></h2><ol><li>Orchestration loop</li><li>Tools</li><li>Filesystem</li><li>Bash / Code execution</li><li>Sandbox</li><li>Memory</li><li>Context management</li><li><strong>Context rot defense</strong> ← 最容易被忽略</li><li>Long-horizon execution</li><li>Error handling / Guardrails</li><li>Serving layer</li></ol><hr><h2 id="ratchet-原則-mitchell-hashimoto" tabindex="-1">Ratchet 原則（Mitchell Hashimoto） <a class="header-anchor" href="#ratchet-原則-mitchell-hashimoto" aria-label="Permalink to &quot;Ratchet 原則（Mitchell Hashimoto）&quot;">​</a></h2><blockquote><p>「Anytime you find an agent makes a mistake, you take the time to engineer a solution such that the agent never makes that mistake again.」</p></blockquote><p>每一條 CLAUDE.md 規則、每一個 hook，都應該追得回某次具體的失敗。</p><p>Addy Osmani 的延伸：「Every line in a good AGENTS.md should be traceable back to a specific thing that went wrong.」</p><hr><h2 id="model-變強之後-body-和-harness-各自的走向" tabindex="-1">Model 變強之後，Body 和 Harness 各自的走向 <a class="header-anchor" href="#model-變強之後-body-和-harness-各自的走向" aria-label="Permalink to &quot;Model 變強之後，Body 和 Harness 各自的走向&quot;">​</a></h2><table tabindex="0"><thead><tr><th>層</th><th>Model 變強後的走向</th><th>原因</th></tr></thead><tbody><tr><td><strong>Body</strong></td><td>長新器官：Computer Use → 多 agent 並行 → 跨 device</td><td>Model 能力提升，body 用得更好、能長更多東西</td></tr><tr><td><strong>Harness</strong></td><td>搬家但不消失：舊 scaffolding 退場，新 scaffolding 長出來</td><td>Harness 解的是 non-determinism 這個結構問題，不是 model 弱的問題</td></tr></tbody></table><p><strong>真正會被 model 進步解掉的 harness</strong>：補弱點用的（subagent for context isolation、early-stop 機制）</p><p><strong>永遠不會消失的 harness</strong>：校準 non-deterministic 系統用的（hooks、verification、planner-evaluator）</p><hr><h2 id="參考資料" tabindex="-1">參考資料 <a class="header-anchor" href="#參考資料" aria-label="Permalink to &quot;參考資料&quot;">​</a></h2><table tabindex="0"><thead><tr><th>來源</th><th>核心貢獻</th></tr></thead><tbody><tr><td>Viv Trivedy / LangChain</td><td>Agent = Model + Harness 原始等式</td></tr><tr><td>HumanLayer《Skill Issue》</td><td>CLAUDE.md + hooks 的具體 harness 工程實踐</td></tr><tr><td>Anthropic 4/23 Postmortem</td><td>三個 harness 級變更的失敗解剖</td></tr><tr><td>Anthropic 《Effective Harnesses》</td><td>跨 session 狀態管理（Initializer + Progress + Git）</td></tr><tr><td>Anthropic 《Harness Design》</td><td>Planner/Generator/Evaluator 三層架構</td></tr><tr><td>Anthropic 《Building Effective Agents》</td><td>六種設計模式；從簡單 prompt 開始</td></tr><tr><td>Chroma 《Context Rot》</td><td>18 個模型的量化衰退數據；NIAH benchmark</td></tr><tr><td>Ewan Mak《70% Rule》</td><td>58%→81% harness 優化實地案例</td></tr><tr><td>Terminal-Bench 2.0</td><td>同模型不同 harness 的 13pp 分數差距</td></tr><tr><td>Simon Willison</td><td>Agentic loop 設計原則；測試套件是 loop 基礎</td></tr><tr><td>Mitchell Hashimoto</td><td>Ratchet 原則：mistake → permanent rule</td></tr><tr><td>Addy Osmani</td><td>AGENTS.md 每行可追蹤到具體失敗</td></tr></tbody></table><hr><h2 id="_2026-05-新論文待閱讀隊列" tabindex="-1">2026-05 新論文待閱讀隊列 <a class="header-anchor" href="#_2026-05-新論文待閱讀隊列" aria-label="Permalink to &quot;2026-05 新論文待閱讀隊列&quot;">​</a></h2><ul><li>[ ] Continual Harness (2605.09998) — Online adaptation; runtime modification without retraining</li><li>[ ] Harness Engineering as Categorical Architecture (2605.12239) — Category theory framework for tool composition</li><li>[ ] AI Harness Engineering: Runtime Substrate (2605.13357) — Execution layer taxonomy</li><li>[ ] Effective Harness Engineering for Algorithm Discovery (2605.15221) — Vesper framework with empirical benchmarks</li><li>[ ] Code as Agent Harness (2605.18747) — Tool schema compilation from code structure</li><li>[ ] Adapting the Interface, Not the Model (2605.22166) — Interface-level runtime adaptation</li><li>[ ] Cheating Agents: Benchmark Manipulation (DebugML 2026-05-23) — Evaluation validity implications</li><li>[ ] Coordination Architectural Layer (2605.03310) — Multi-agent coordination layer</li><li>[ ] HeavySkill (2605.02396) — Extended reasoning within skill invocations</li></ul>`,64)])])}const g=a(r,[["render",o]]);export{u as __pageData,g as default};
